eql.source:
update LitemallOrder
set orderStatus = ${newStatus}
where id = ${orderId} and orderStatus = ${expectedStatus}

sql.source:
SELECT PAY_TIME AS PAY_TIME, ACTUAL_PRICE AS ACTUAL_PRICE
FROM litemall_order
WHERE CAST(DELETED AS INT) = 0
  AND CAST(ORDER_STATUS AS INT) >= 201
  AND PAY_TIME >= ${startDate}
  AND PAY_TIME <= ${endDate}

SELECT c.GOODS_ID AS GOODS_ID, MAX(c.GOODS_NAME) AS GOODS_NAME, COUNT(*) AS CART_COUNT
FROM litemall_cart c

INNER JOIN litemall_goods g ON g.ID = c.GOODS_ID AND CAST(g.DELETED AS INT) = 0

WHERE CAST(c.DELETED AS INT) = 0
  AND c.ADD_TIME >= ${startDate}
  AND c.ADD_TIME <= ${endDate}

  AND g.CATEGORY_ID = ${categoryId}

GROUP BY c.GOODS_ID
ORDER BY CART_COUNT DESC
LIMIT ${limit}

SELECT g.ID AS GOODS_ID, g.NAME AS GOODS_NAME
FROM litemall_goods g
WHERE CAST(g.DELETED AS INT) = 0
  AND CAST(g.IS_ON_SALE AS INT) = 1

  AND g.CATEGORY_ID = ${categoryId}

  AND NOT EXISTS (
    SELECT 1 FROM litemall_order_goods og
    INNER JOIN litemall_order o ON o.ID = og.ORDER_ID
    WHERE CAST(og.DELETED AS INT) = 0 AND CAST(o.DELETED AS INT) = 0
      AND CAST(o.ORDER_STATUS AS INT) NOT IN (102, 103)
      AND og.GOODS_ID = g.ID
      AND o.ADD_TIME >= ${startDate}
      AND o.ADD_TIME <= ${endDate}
  )
LIMIT ${limit}

SELECT COUNT(DISTINCT og.GOODS_ID) AS TOTAL_COUNT
FROM litemall_order_goods og
INNER JOIN litemall_order o ON o.ID = og.ORDER_ID

INNER JOIN litemall_goods g ON g.ID = og.GOODS_ID AND CAST(g.DELETED AS INT) = 0

WHERE CAST(o.DELETED AS INT) = 0 AND CAST(og.DELETED AS INT) = 0
  AND CAST(o.ORDER_STATUS AS INT) NOT IN (102, 103)
  AND o.ADD_TIME >= ${startDate}
  AND o.ADD_TIME <= ${endDate}

  AND g.CATEGORY_ID = ${categoryId}

SELECT og.GOODS_ID AS GOODS_ID, og.GOODS_NAME AS GOODS_NAME, SUM(og.NUMBER) AS SALES_COUNT, SUM(og.PRICE * og.NUMBER) AS SALES_AMOUNT FROM litemall_order_goods og INNER JOIN litemall_order o ON o.ID = og.ORDER_ID
INNER JOIN litemall_goods g ON g.ID = og.GOODS_ID AND CAST(g.DELETED AS INT) = 0
WHERE CAST(o.DELETED AS INT) = 0 AND CAST(og.DELETED AS INT) = 0 AND CAST(o.ORDER_STATUS AS INT) NOT IN (102, 103) AND o.ADD_TIME >= ${startDate} AND o.ADD_TIME <= ${endDate}
AND g.CATEGORY_ID = ${categoryId}
GROUP BY og.GOODS_ID, og.GOODS_NAME ORDER BY SALES_COUNT DESC LIMIT ${limit}
